import sys
import math

def compute_lcm(a, b, c):
    lcm_ab = (a * b) // math.gcd(a, b)
    lcm_abc = (lcm_ab * c) // math.gcd(lcm_ab, c)
    return lcm_abc

def max_lcm_three_numbers(n):
    if n < 3:
        return n
    candidates = []
    # Consider the largest numbers and their combinations
    candidates.append(n)
    if n - 1 > 0:
        candidates.append(n - 1)
    if n - 2 > 0:
        candidates.append(n - 2)
    if n - 3 > 0:
        candidates.append(n - 3)
    # Also consider cases like n, n-1, n-3 if n is even
    max_lcm = 0
    # Check all possible combinations of three distinct candidates
    for i in range(len(candidates)):
        for j in range(i + 1, len(candidates)):
            for k in range(j + 1, len(candidates)):
                current_lcm = compute_lcm(candidates[i], candidates[j], candidates[k])
                if current_lcm > max_lcm:
                    max_lcm = current_lcm
    # Also consider cases where numbers are repeated (like n, n, n-1)
    if n >= 2:
        current_lcm = compute_lcm(n, n, n - 1)
        if current_lcm > max_lcm:
            max_lcm = current_lcm
    if n >= 3:
        current_lcm = compute_lcm(n, n - 1, n - 1)
        if current_lcm > max_lcm:
            max_lcm = current_lcm
    return max_lcm

n = int(sys.stdin.readline())
print(max_lcm_three_numbers(n))
